diff --git a/src/app/pages/HomePage/Features/GithubRepoForm/__tests__/RepoItem.test.tsx b/src/app/pages/HomePage/Features/GithubRepoForm/__tests__/RepoItem.test.tsx
new file mode 100644
index 0000000..2d52ba0
--- /dev/null
+++ b/src/app/pages/HomePage/Features/GithubRepoForm/__tests__/RepoItem.test.tsx
@@ -0,0 +1,40 @@
+import * as React from 'react';
+import { render } from '@testing-library/react';
+import { RepoItem } from '../RepoItem';
+
+const renderRepoItem = (props: Parameters<typeof RepoItem>[number]) =>
+  render(<RepoItem {...props} />);
+
+describe('<RepoItem />', () => {
+  it('should match the snapshot', () => {
+    const repoItem = renderRepoItem({
+      name: 'test',
+      starCount: 1,
+      url: 'testUrl',
+    });
+    expect(repoItem.container.firstChild).toMatchSnapshot();
+  });
+
+  it('should have url in <a> child', () => {
+    const url = 'url1';
+    const repoItem = renderRepoItem({
+      name: 'test',
+      starCount: 1,
+      url: url,
+    });
+    expect(repoItem.container.querySelector('a')).toHaveAttribute('href', url);
+  });
+
+  it('should have props displayed', () => {
+    const url = 'url1';
+    const starCount = 1;
+    const name = 'test';
+    const repoItem = renderRepoItem({
+      name: name,
+      starCount: starCount,
+      url: url,
+    });
+    expect(repoItem.queryByText(name)).toBeInTheDocument();
+    expect(repoItem.queryByText(starCount.toString())).toBeInTheDocument();
+  });
+});

diff --git a/src/app/pages/HomePage/Features/GithubRepoForm/__tests__/saga.test.ts b/src/app/pages/HomePage/Features/GithubRepoForm/__tests__/saga.test.ts
new file mode 100644
index 0000000..d9ce24b
--- /dev/null
+++ b/src/app/pages/HomePage/Features/GithubRepoForm/__tests__/saga.test.ts
@@ -0,0 +1,110 @@
+import { put, takeLatest } from 'redux-saga/effects';
+import * as slice from '../slice';
+
+import { githubRepoFormSaga, getRepos } from '../saga';
+import { RepoErrorType } from '../types';
+
+describe('getRepos Saga', () => {
+  let username: any;
+  let repos: any;
+  let getReposIterator: ReturnType<typeof getRepos>;
+
+  // We have to test twice, once for a successful load and once for an unsuccessful one
+  // so we do all the stuff that happens beforehand automatically in the beforeEach
+  beforeEach(() => {
+    getReposIterator = getRepos();
+    const delayDescriptor = getReposIterator.next().value;
+    expect(delayDescriptor).toMatchSnapshot();
+
+    const selectDescriptor = getReposIterator.next().value;
+    expect(selectDescriptor).toMatchSnapshot();
+  });
+
+  it('should return error if username is empty', () => {
+    username = '';
+    const putDescriptor = getReposIterator.next(username).value;
+    expect(putDescriptor).toEqual(
+      put(slice.actions.repoError(RepoErrorType.USERNAME_EMPTY)),
+    );
+
+    const iteration = getReposIterator.next();
+    expect(iteration.done).toBe(true);
+  });
+
+  it('should dispatch the reposLoaded action if it requests the data successfully', () => {
+    username = 'test';
+    repos = [
+      {
+        name: 'repo1',
+        owner: {
+          login: 'username1',
+        },
+      },
+    ];
+
+    const requestDescriptor = getReposIterator.next(username).value;
+    expect(requestDescriptor).toMatchSnapshot();
+
+    const putDescriptor = getReposIterator.next(repos).value;
+    expect(putDescriptor).toEqual(put(slice.actions.reposLoaded(repos)));
+  });
+
+  it('should dispatch the user not found error', () => {
+    username = 'test';
+
+    const requestDescriptor = getReposIterator.next(username).value;
+    expect(requestDescriptor).toMatchSnapshot();
+
