diff --git a/src/app/pages/HomePage/__tests__/Features.test.tsx b/src/app/pages/HomePage/__tests__/Features.test.tsx
new file mode 100644
index 0000000..0fcb416
--- /dev/null
+++ b/src/app/pages/HomePage/__tests__/Features.test.tsx
@@ -0,0 +1,34 @@
+import * as React from 'react';
+import { createRenderer } from 'react-test-renderer/shallow';
+import { Features } from '../Features';
+import i18next from 'i18next';
+
+const shallowRenderer = createRenderer();
+
+describe('<Features />', () => {
+  it('should render with en translations', () => {
+    i18next.changeLanguage('en');
+    shallowRenderer.render(<Features />);
+    const renderedOutput = shallowRenderer.getRenderOutput();
+    expect(renderedOutput).toMatchSnapshot();
+  });
+
+  it('should render with de translations', () => {
+    i18next.changeLanguage('de');
+    shallowRenderer.render(<Features />);
+    const renderedOutput = shallowRenderer.getRenderOutput();
+    expect(renderedOutput).toMatchSnapshot();
+  });
+
+  it('should render different after language change', () => {
+    i18next.changeLanguage('en');
+    shallowRenderer.render(<Features />);
+    const renderedOutput1 = shallowRenderer.getRenderOutput();
+
+    i18next.changeLanguage('de');
+    shallowRenderer.render(<Features />);
+    const renderedOutput2 = shallowRenderer.getRenderOutput();
+
+    expect(renderedOutput1).not.toEqual(renderedOutput2);
+  });
+});

diff --git a/src/app/pages/HomePage/__tests__/Logos.test.tsx b/src/app/pages/HomePage/__tests__/Logos.test.tsx
new file mode 100644
index 0000000..68a198f
--- /dev/null
+++ b/src/app/pages/HomePage/__tests__/Logos.test.tsx
@@ -0,0 +1,30 @@
+import * as React from 'react';
+import { Logos } from '../Logos';
+import { render } from '@testing-library/react';
+import { ThemeProvider, DefaultTheme } from 'styled-components';
+
+import { themes } from 'styles/theme/themes';
+
+const renderLogos = (theme: DefaultTheme) =>
+  render(
+    <ThemeProvider theme={theme}>
+      <Logos />
+    </ThemeProvider>,
+  );
+describe('<Logos />', () => {
+  it('should render and match the snapshot', () => {
+    const logos = renderLogos(themes.light);
+    expect(logos.asFragment()).toMatchSnapshot();
+  });
+
+  it('should use theme from props', () => {
+    let logos = renderLogos(themes.light);
+    expect(logos.container.firstChild).toHaveStyle(
+      `color: ${themes.light.border}`,
+    );
+    logos = renderLogos(themes.dark);
+    expect(logos.container.firstChild).toHaveStyle(
+      `color: ${themes.dark.border}`,
+    );
+  });
+});

